const HOTEL_MARKUP = 1.15;
const CAR_MARKUP   = 1.20;

const dmc          = $('Check DMC Partners (Google Sheet)').all().map(i => i.json) || [];
const amadeusHotels= $('Amadeus Hotels Search').first()?.json?.data?.slice(0,2) || [];
const bookingHotels= $('Booking.com Hotel Search').first()?.json?.result?.slice(0,2) || [];
const hotelbedsData= $('Hotelbeds Search').first()?.json?.hotels?.hotels?.slice(0,2) || [];
const req          = $('Extract Package Request').first().json;

let options = '*🏨 Package Options — Jude Travel Agency*

';
let idx = 1;

// Jordan Pass integration
if (req.wants_jordan_pass) {
  options += `*🇯🇴 Jordan Pass Included*\n`;
  options += `Access to 40+ attractions including Petra, Wadi Rum, Jerash\n`;
  options += `Save up to 70 JOD on entrance fees\n\n`;
}
// Dead Sea resort categorization
const isDeadSea = ['dead sea', 'deadsea', 'mayyit', 'bahr lut'].some(term =>
  req.destination.toLowerCase().includes(term));

// DMC Partners — no markup (already includes margin)
dmc.slice(0,2).forEach(d => {
  options += `*Option ${idx++}*
`;
  options += `Hotel: ${d.hotel_name || 'Premium Hotel'}
`;
  options += `Location: ${d.location || req.destination}
`;
  options += `Price/Night: ${d.price_per_night || 'TBD'} ${d.currency || 'SAR'}
`;
  options += `Includes: ${d.inclusions || 'Breakfast, Transfers'}
`;
  if (d.car_rental && d.car_rental_price) {
    const carPrice = (parseFloat(d.car_rental_price) * CAR_MARKUP).toFixed(2);
    options += `Car Rental: ${carPrice} ${d.currency || 'SAR'}/day
`;
  }
  options += '\n';
});

// Amadeus Hotels — 15% markup
amadeusHotels.forEach(h => {
  const rawPrice = parseFloat(h.offers?.[0]?.price?.total || 0);
  const finalPrice = rawPrice > 0 ? (rawPrice * HOTEL_MARKUP).toFixed(2) : 'Contact for price';
  const currency = h.offers?.[0]?.price?.currency || 'USD';
  options += `*Option ${idx++}*
`;
  options += `Hotel: ${h.hotel?.name || 'Quality Hotel'}
`;
  options += `Location: ${h.hotel?.cityCode || req.destination}
`;
  options += `Price/Night: ${finalPrice} ${currency}

`;
});

// Booking.com — 15% markup
bookingHotels.forEach(h => {
  const rawPrice = parseFloat(h.min_rate || 0);
  const finalPrice = rawPrice > 0 ? (rawPrice * HOTEL_MARKUP).toFixed(2) : 'Contact for price';
  options += `*Option ${idx++}*
`;
  options += `Hotel: ${h.name || h.hotel_name}
`;
  options += `Stars: ${'⭐'.repeat(Math.min(h.class || 4, 5))}
`;
  options += `Price/Night: ${finalPrice} ${h.currency_code || 'USD'}

`;
});

// Hotelbeds — 15% markup
hotelbedsData.forEach(h => {
  const rawPrice = parseFloat(h.minRate || 0);
  const finalPrice = rawPrice > 0 ? (rawPrice * HOTEL_MARKUP).toFixed(2) : 'Contact for price';
  const hotelName = Array.isArray(h.name) ? h.name[0]?.content : (h.name || 'Quality Hotel');
  options += `*Option ${idx++}*
`;
  options += `Hotel: ${hotelName}
`;
  options += `Stars: ${'⭐'.repeat(Math.min(parseInt(h.categoryCode) || 4, 5))}
`;
  options += `Price/Night: ${finalPrice} ${h.currency || 'USD'}

`;
});

options += 'Reply with option number to proceed. / رد برقم الخيار للمتابعة.';
return [{ json: {
  package_options: options,
  sender_id:     req.sender_id,
  customer_name: req.customer_name,
  destination:   req.destination
} }];

